import os

def get_ls_result(dir_path: str) -> str:
    try:
        # Validate that the path exists and is a directory
        if not os.path.exists(dir_path) or not os.path.isdir(dir_path):
            return ""

        # Validate path to prevent directory traversal
        normalized_path = os.path.normpath(os.path.abspath(dir_path))
        if not normalized_path.startswith(os.path.abspath('.')):
            return ""

        # Use os.listdir instead of subprocess for security
        entries = []
        for item in os.listdir(normalized_path):
            item_path = os.path.join(normalized_path, item)
            stat_info = os.stat(item_path)

            # Format similar to ls -l output
            mode = oct(stat_info.st_mode)[-3:]
            size = stat_info.st_size
            entries.append(f"{mode} {size} {item}")

        return '\n'.join(entries)

    except (OSError, ValueError, PermissionError):
        return ""

