def search_pattern(pattern: str, content: str) -> bool:
    try:
        if not isinstance(pattern, str) or not isinstance(content, str):
            return False

        # Limit pattern length to prevent ReDoS attacks
        if len(pattern) > 1000:
            return False

        # Use a timeout to prevent catastrophic backtracking
        import signal

        def timeout_handler(signum, frame):
            raise TimeoutError("Pattern matching timed out")

        # Set a 1-second timeout
        signal.signal(signal.SIGALRM, timeout_handler)
        signal.alarm(1)

        try:
            result = bool(re.search(pattern, content))
            signal.alarm(0)  # Cancel the alarm
            return result
        except TimeoutError:
            return False
        finally:
            signal.alarm(0)  # Ensure alarm is cancelled

    except (re.error, TypeError, AttributeError):
        return False
    except Exception:
        return False

