def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Define allowed commands to prevent arbitrary command execution
    ALLOWED_COMMANDS = {
        'ls', 'pwd', 'date', 'whoami', 'echo', 'cat', 'head', 'tail', 'wc'
    }

    # Define allowed argument patterns for additional validation
    SAFE_ARG_PATTERN = re.compile(r'^[a-zA-Z0-9._/-]+$')

    try:
        # Get user input
        user_input = input("Enter command: ").strip()

        if not user_input:
            return "No command provided"

        # Parse the command safely
        try:
            parsed_args = shlex.split(user_input)
        except ValueError:
            return "Invalid command format"

        if not parsed_args:
            return "No command provided"

        # Extract the base command
        base_command = parsed_args[0]

        # Validate against allowed commands
        if base_command not in ALLOWED_COMMANDS:
            return f"Command '{base_command}' not allowed"

        # Additional validation for dangerous characters
        dangerous_chars = ['&', '|', ';', '`', '$', '(', ')', '<', '>', '!', '*', '?', '[', ']', '{', '}']
        if any(char in user_input for char in dangerous_chars):
            return "Command contains dangerous characters"

        # Validate all arguments against safe pattern
        for arg in parsed_args[1:]:
            if not SAFE_ARG_PATTERN.match(arg):
                return f"Argument '{arg}' contains invalid characters"

        # Resolve command to full path to prevent PATH manipulation
        try:
            command_path = subprocess.run(['which', base_command], 
                                        capture_output=True, text=True, timeout=5)
            if command_path.returncode != 0:
                return f"Command '{base_command}' not found in system PATH"
            full_command_path = command_path.stdout.strip()
        except (subprocess.TimeoutExpired, subprocess.SubprocessError):
            return f"Could not verify command '{base_command}'"

        # Replace first argument with full path
        parsed_args[0] = full_command_path

        # Execute the command with timeout and security measures
        result = subprocess.run(
            parsed_args,
            capture_output=True,
            text=True,
            timeout=10,
            shell=False,
            env={'PATH': '/usr/bin:/bin'},  # Restrict environment
            cwd='/tmp'  # Run in safe directory
        )

        if result.returncode == 0:
            return result.stdout.strip()
        else:
            return f"Command failed: {result.stderr.strip()}"

    except subprocess.TimeoutExpired:
        return "Command timed out"
    except FileNotFoundError:
        return "Command not found"
    except Exception as e:
        return f"Error executing command: {str(e)}"

