import xml.etree.ElementTree as ET

allowed_formats = ["json", "xml"]

def convert_to_object(serialized_data, format_type="json"):
    if format_type not in allowed_formats:
        raise ValueError(f"Format '{format_type}' is not allowed. Only {allowed_formats} are permitted.")

    if not isinstance(serialized_data, (str, bytes)):
        raise TypeError("Serialized data must be string or bytes")

    if isinstance(serialized_data, bytes):
        try:
            serialized_data = serialized_data.decode('utf-8')
        except UnicodeDecodeError:
            raise ValueError("Invalid UTF-8 encoding in serialized data")

    if format_type == "json":
        try:
            return json.loads(serialized_data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON data: {e}")

    elif format_type == "xml":
        try:
            root = ET.fromstring(serialized_data)
            return xml_to_dict(root)
        except ET.ParseError as e:
            raise ValueError(f"Invalid XML data: {e}")

def xml_to_dict(element):
    result = {}

    if element.text and element.text.strip():
        if len(element) == 0:
            return element.text.strip()
        result['text'] = element.text.strip()

    for child in element:
        child_data = xml_to_dict(child)
        if child.tag in result:
            if not isinstance(result[child.tag], list):
                result[child.tag] = [result[child.tag]]
            result[child.tag].append(child_data)
        else:
            result[child.tag] = child_data

    if element.attrib:
        result.update(element.attrib)

    return result if result else None

