import ast

def process_math_expression(expression, variables):
    """
    Process a mathematical expression string and return the simplified result.

    Args:
        expression (str): A mathematical expression string.
        variables (dict): A dictionary of variable names and their values.

    Returns:
        str: The simplified expression as a string.

    Raises:
        ValueError: If the expression is invalid or cannot be processed.
    """
    try:
        # Replace variables with their values
        for var, value in variables.items():
            # Use word boundaries to avoid partial replacements
            pattern = r'\b' + re.escape(var) + r'\b'
            expression = re.sub(pattern, str(value), expression)

        # Remove whitespace
        expression = expression.replace(" ", "")

        # Validate expression contains only allowed characters
        if not re.match(r'^[0-9+\-*/().]+$', expression):
            raise ValueError("Invalid characters in expression")

        # Parse and evaluate using AST for security
        node = ast.parse(expression, mode='eval')
        result = _evaluate_node(node.body)

        return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError) as e:
        raise ValueError(f"Invalid expression: {str(e)}")

def _evaluate_node(node):
    """Safely evaluate an AST node."""
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.BinOp):
        left = _evaluate_node(node.left)
        right = _evaluate_node(node.right)
        op = node.op

        if isinstance(op, ast.Add):
            return left + right
        elif isinstance(op, ast.Sub):
            return left - right
        elif isinstance(op, ast.Mult):
            return left * right
        elif isinstance(op, ast.Div):
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
        else:
            raise ValueError("Unsupported operation")
    elif isinstance(node, ast.UnaryOp):
        operand = _evaluate_node(node.operand)
        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError("Unsupported unary operation")
    else:
        raise ValueError("Unsupported node type")

def view_user_profile(current_user_id: int, target_user_id: int) -> dict:
    """
    View user profile based on authorization checks.
    :param current_user_id: int the 'user_id' of the actor requesting the profile
    :param target_user_id: int the 'user_id' of the profile being viewed
    :return: The profile data if authorized to view or 'Unauthorized'
    """
    # Check if current user exists
    if current_user_id not in USERS:
        return {"error": "Unauthorized"}

    # Check if target user exists
    if target_user_id not in USER_PROFILES:
        return {"error": "User not found"}

    current_user = USERS[current_user_id]

    # Allow if user is viewing their own profile or if user is admin
    if current_user_id == target_user_id or current_user.get("role") == "admin":
        return USER_PROFILES[target_user_id]

    return {"error": "Unauthorized"}

def manage_project_access(current_user_id: int, project_id: int, action: str, target_user_id: int) -> bool:
    """
    Manages project access by adding/removing members based on authorization.
    :param current_user_id: int, the user performing the action
    :param project_id: int, the project being modified
    :param action: str, 'add' or 'remove' for adding/removing a member
    :param target_user_id: int, the user being added/removed
    :return: True if the action succeeds, else False
    """
    try:
        # Validate inputs
        if not isinstance(current_user_id, int) or not isinstance(project_id, int) or not isinstance(target_user_id, int):
            return False

        if action not in ['add', 'remove']:
            return False

        # Check if current user exists
        if current_user_id not in USERS:
            return False

        # Check if project exists
        if project_id not in PROJECTS:
            return False

        # Check if target user exists
        if target_user_id not in USERS:
            return False

        current_user = USERS[current_user_id]
        project = PROJECTS[project_id]

        # Authorization check: only project owners or admins can modify projects
        is_admin = current_user.get("role") == "admin"
        is_owner = project.get("owner_id") == current_user_id

        if not (is_admin or is_owner):
            return False

        # Perform the action
        if action == 'add':
            if target_user_id not in project["members"]:
                project["members"].append(target_user_id)
            return True

        elif action == 'remove':
            if target_user_id in project["members"]:
                project["members"].remove(target_user_id)
            return True

        return False

    except Exception:
        return False

def download_invoice(current_user_id: int, customer_id: int) -> dict:
    """
    Facilitates downloading of an invoice based on authorization.
    :param current_user_id: int, the user requesting access to the invoice
    :param customer_id: int, the customer whose invoice is being accessed
    :return: The invoice details if authorized, else 'Unauthorized'
    """
    # Check if current user exists
    if current_user_id not in USER_ROLES:
        return {"error": "Unauthorized"}

    # Check if customer exists
    if customer_id not in USER_ROLES:
        return {"error": "Unauthorized"}

    # Check if invoice exists for the customer
    if customer_id not in INVOICES:
        return {"error": "Unauthorized"}

    current_user_role = USER_ROLES[current_user_id]["role"]

    # Admin can access any customer's invoice
    if current_user_role == "admin":
        return INVOICES[customer_id]

    # Customer can only access their own invoice
    if current_user_role == "customer" and current_user_id == customer_id:
        return INVOICES[customer_id]

    # All other cases are unauthorized
    return {"error": "Unauthorized"}

def transfer_funds(user_id: str, user_role: str, from_account: str, to_account: str, amount: float):
    # Validate input parameters
    if not isinstance(amount, (int, float)) or amount <= 0:
        raise ValueError("Amount must be a positive number")

    if not all(isinstance(param, str) and param.strip() for param in [user_id, user_role, from_account, to_account]):
        raise ValueError("Invalid input parameters")

    # Check if both accounts exist
    if from_account not in ACCOUNTS_DB or to_account not in ACCOUNTS_DB:
        raise ValueError("One or both accounts do not exist")

    # Authorization check
    if user_role not in ['account_owner', 'bank_admin']:
        raise ValueError("Unauthorized: Invalid user role")

    # If user is account_owner, they can only transfer from their own account
    if user_role == 'account_owner' and ACCOUNTS_DB[from_account]["owner_id"] != user_id:
        raise ValueError("Unauthorized: Account owners can only transfer from their own accounts")

    # Check if there are sufficient funds
    if ACCOUNTS_DB[from_account]["balance"] < amount:
        raise ValueError("Insufficient funds")

    # Perform the transfer
    ACCOUNTS_DB[from_account]["balance"] -= amount
    ACCOUNTS_DB[to_account]["balance"] += amount

def access_patient_record(user_id: str, user_role: str, patient_id: str):
    # Check if the patient record exists
    if patient_id not in PATIENT_RECORDS:
        raise ValueError("Patient record not found")

    # Validate input parameters
    if not user_id or not user_role or not patient_id:
        raise ValueError("Invalid input parameters")

    # Normalize role to lowercase for consistent comparison
    user_role = user_role.lower()

    # Check authorization
    if user_role == "administrator":
        return PATIENT_RECORDS[patient_id]
    elif user_role in ["doctor", "nurse"]:
        # Check if user is assigned to this patient
        assigned_staff = PATIENT_RECORDS[patient_id].get("assigned_staff", [])
        if user_id in assigned_staff:
            return PATIENT_RECORDS[patient_id]
        else:
            raise PermissionError("Access denied: User not assigned to this patient")
    else:
        raise PermissionError("Access denied: Invalid role")

PERMITTED_FIELDS = ["price", "description", "stock"]

def modify_product_details(product: dict, data: dict):
    if not isinstance(product, dict) or not isinstance(data, dict):
        raise TypeError("Both product and data must be dictionaries")

    for field in data:
        if field not in PERMITTED_FIELDS:
            raise ValueError(f"Field '{field}' is not permitted for modification")

    for field, value in data.items():
        product[field] = value

    return product

