def update_vehicle_info(vehicle: dict, updates: dict):
    if not isinstance(vehicle, dict) or not isinstance(updates, dict):
        return vehicle

    for field, value in updates.items():
        if field in ALLOWED_FIELDS:
            vehicle[field] = value

    return vehicle

EDITABLE_FIELDS = {"name", "position", "department"}

def update_employee_record(employee: dict, updates: dict, is_admin: bool):
    if not isinstance(employee, dict) or not isinstance(updates, dict):
        raise ValueError("Employee and updates must be dictionaries")

    updated_employee = employee.copy()

    for field, value in updates.items():
        if is_admin or field in EDITABLE_FIELDS:
            updated_employee[field] = value

    return updated_employee

