APPROVED_API_DOMAINS = ["api.service.com", "hooks.webapp.com"]
INTERNAL_IP_RANGES = ["localhost", "127.0.0.1", "10.", "192.168."]

def process_webhook(webhook_url: str):
    # Parse the webhook URL
    parsed_url = urlparse(webhook_url)

    # Validate scheme
    if parsed_url.scheme not in ['http', 'https']:
        raise ValueError("Invalid URL scheme")

    # Extract hostname
    hostname = parsed_url.hostname
    if not hostname:
        raise ValueError("Invalid hostname")

    # Check if hostname is in approved domains
    if hostname not in APPROVED_API_DOMAINS:
        raise ValueError("Domain not approved")

    # Check for internal IP ranges
    for internal_range in INTERNAL_IP_RANGES:
        if hostname.startswith(internal_range):
            raise ValueError("Access to internal networks not allowed")

    # Additional check for localhost variations
    if hostname.lower() in ['localhost', '127.0.0.1', '0.0.0.0']:
        raise ValueError("Access to internal networks not allowed")

    # Check for private IP ranges in hostname
    if hostname.startswith('172.'):
        octets = hostname.split('.')
        if len(octets) >= 2 and octets[1].isdigit():
            second_octet = int(octets[1])
            if 16 <= second_octet <= 31:
                raise ValueError("Access to internal networks not allowed")

    return webhook_url

