def execute_code_snippet(code_snippet: str):
    # Parse the code into an AST
    try:
        tree = ast.parse(code_snippet, mode='exec')
    except SyntaxError:
        raise ValueError("Invalid Python syntax")

    # Define allowed node types for harmless operations
    allowed_nodes = {
        ast.Module, ast.Expr, ast.Assign, ast.AugAssign, ast.Name, ast.Store, ast.Load,
        ast.Constant, ast.Num, ast.Str, ast.NameConstant,  # For older Python versions
        ast.BinOp, ast.UnaryOp, ast.Compare, ast.BoolOp,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow,
        ast.LShift, ast.RShift, ast.BitOr, ast.BitXor, ast.BitAnd,
        ast.And, ast.Or, ast.Not, ast.Invert, ast.UAdd, ast.USub,
        ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE, ast.Is, ast.IsNot, ast.In, ast.NotIn,
        ast.List, ast.Tuple, ast.Dict, ast.Set,
        ast.Index, ast.Slice, ast.ExtSlice, ast.Subscript,  # For indexing operations
        ast.ListComp, ast.DictComp, ast.SetComp, ast.GeneratorExp,
        ast.comprehension, ast.keyword, ast.alias
    }

    # Check all nodes in the AST
    for node in ast.walk(tree):
        if type(node) not in allowed_nodes:
            raise ValueError(f"Operation not allowed: {type(node).__name__}")

        # Additional checks for specific dangerous operations
        if isinstance(node, ast.Name):
            # Block dangerous built-in functions
            dangerous_names = {
                'exec', 'eval', 'compile', '__import__', 'open', 'input', 'raw_input',
                'file', 'execfile', 'reload', 'vars', 'locals', 'globals', 'dir',
                'hasattr', 'getattr', 'setattr', 'delattr', 'callable'
            }
            if node.id in dangerous_names:
                raise ValueError(f"Access to '{node.id}' is not allowed")

    # Create a restricted execution environment
    safe_globals = {
        '__builtins__': {
            'abs': abs, 'all': all, 'any': any, 'bin': bin, 'bool': bool,
            'chr': chr, 'complex': complex, 'dict': dict, 'divmod': divmod,
            'enumerate': enumerate, 'filter': filter, 'float': float,
            'frozenset': frozenset, 'hex': hex, 'int': int, 'len': len,
            'list': list, 'map': map, 'max': max, 'min': min, 'oct': oct,
            'ord': ord, 'pow': pow, 'range': range, 'reversed': reversed,
            'round': round, 'set': set, 'sorted': sorted, 'str': str,
            'sum': sum, 'tuple': tuple, 'type': type, 'zip': zip,
            'True': True, 'False': False, 'None': None
        }
    }

    safe_locals = {}

    # Execute the code
    try:
        exec(compile(tree, '<string>', 'exec'), safe_globals, safe_locals)
        return safe_locals
    except Exception as e:
        raise ValueError(f"Execution error: {str(e)}")

import ast
import operator

def execute_code_snippet(code_snippet: str):
    # Parse the code into an AST
    try:
        tree = ast.parse(code_snippet, mode='exec')
    except SyntaxError:
        raise ValueError("Invalid Python syntax")

    # Define allowed node types for harmless operations
    allowed_nodes = {
        ast.Module, ast.Expr, ast.Assign, ast.AugAssign, ast.Name, ast.Store, ast.Load,
        ast.Constant, ast.Num, ast.Str, ast.NameConstant,  # For older Python versions
        ast.BinOp, ast.UnaryOp, ast.Compare, ast.BoolOp,
        ast.Add, ast.Sub, ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, ast.Pow,
        ast.LShift, ast.RShift, ast.BitOr, ast.BitXor, ast.BitAnd,
        ast.And, ast.Or, ast.Not, ast.Invert, ast.UAdd, ast.USub,
        ast.Eq, ast.NotEq, ast.Lt, ast.LtE, ast.Gt, ast.GtE, ast.Is, ast.IsNot, ast.In, ast.NotIn,
        ast.List, ast.Tuple, ast.Dict, ast.Set,
        ast.Index, ast.Slice, ast.ExtSlice, ast.Subscript,  # For indexing operations
        ast.ListComp, ast.DictComp, ast.SetComp, ast.GeneratorExp,
        ast.comprehension, ast.keyword, ast.alias
    }

    # Check all nodes in the AST
    for node in ast.walk(tree):
        if type(node) not in allowed_nodes:
            raise ValueError(f"Operation not allowed: {type(node).__name__}")

        # Additional checks for specific dangerous operations
        if isinstance(node, ast.Name):
            # Block dangerous built-in functions
            dangerous_names = {
                'exec', 'eval', 'compile', '__import__', 'open', 'input', 'raw_input',
                'file', 'execfile', 'reload', 'vars', 'locals', 'globals', 'dir',
                'hasattr', 'getattr', 'setattr', 'delattr', 'callable'
            }
            if node.id in dangerous_names:
                raise ValueError(f"Access to '{node.id}' is not allowed")

    # Safe AST evaluator
    class SafeEvaluator(ast.NodeVisitor):
        def __init__(self):
            self.variables = {}
            self.operators = {
                ast.Add: operator.add,
                ast.Sub: operator.sub,
                ast.Mult: operator.mul,
                ast.Div: operator.truediv,
                ast.FloorDiv: operator.floordiv,
                ast.Mod: operator.mod,
                ast.Pow: operator.pow,
                ast.LShift: operator.lshift,
                ast.RShift: operator.rshift,
                ast.BitOr: operator.or_,
                ast.BitXor: operator.xor,
                ast.BitAnd: operator.and_,
                ast.And: lambda x, y: x and y,
                ast.Or: lambda x, y: x or y,
                ast.Eq: operator.eq,
                ast.NotEq: operator.ne,
                ast.Lt: operator.lt,
                ast.LtE: operator.le,
                ast.Gt: operator.gt,
                ast.GtE: operator.ge,
                ast.Is: operator.is_,
                ast.IsNot: operator.is_not,
                ast.In: lambda x, y: x in y,
                ast.NotIn: lambda x, y: x not in y,
            }
            self.unary_operators = {
                ast.UAdd: operator.pos,
                ast.USub: operator.neg,
                ast.Not: operator.not_,
                ast.Invert: operator.invert,
            }

        def visit_Module(self, node):
            for stmt in node.body:
                self.visit(stmt)
            return self.variables

        def visit_Assign(self, node):
            value = self.visit(node.value)
            for target in node.targets:
                if isinstance(target, ast.Name):
                    self.variables[target.id] = value

        def visit_Expr(self, node):
            return self.visit(node.value)

        def visit_Name(self, node):
            if node.id in self.variables:
                return self.variables[node.id]
            elif node.id in {'True', 'False', 'None'}:
                return {'True': True, 'False': False, 'None': None}[node.id]
            else:
                raise ValueError(f"Undefined variable: {node.id}")

        def visit_Constant(self, node):
            return node.value

        def visit_Num(self, node):  # For older Python versions
            return node.n

        def visit_Str(self, node):  # For older Python versions
            return node.s

        def visit_NameConstant(self, node):  # For older Python versions
            return node.value

        def visit_BinOp(self, node):
            left = self.visit(node.left)
            right = self.visit(node.right)
            op = self.operators[type(node.op)]
            return op(left, right)

        def visit_UnaryOp(self, node):
            operand = self.visit(node.operand)
            op = self.unary_operators[type(node.op)]
            return op(operand)

        def visit_Compare(self, node):
            left = self.visit(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                right = self.visit(comparator)
                op_func = self.operators[type(op)]
                if not op_func(left, right):
                    return False
                left = right
            return True

        def visit_List(self, node):
            return [self.visit(elt) for elt in node.elts]

        def visit_Tuple(self, node):
            return tuple(self.visit(elt) for elt in node.elts)

        def visit_Dict(self, node):
            return {self.visit(k): self.visit(v) for k, v in zip(node.keys, node.values)}

        def visit_Set(self, node):
            return {self.visit(elt) for elt in node.elts}

    # Execute the code safely
    try:
        evaluator = SafeEvaluator()
        return evaluator.visit(tree)
    except Exception as e:
        raise ValueError(f"Execution error: {str(e)}")

import re

def process_user_query(query: str):
    # Remove whitespace
    query = query.strip()

    # Check if query contains only allowed characters: digits, operators, parentheses, decimal points
    if not re.match(r'^[0-9+\-*/().\s]+$', query):
        raise ValueError("Invalid characters in expression")

    # Check for empty query
    if not query:
        raise ValueError("Empty query")

    # Additional security checks to prevent malicious patterns
    # Prevent multiple consecutive operators (except for negative numbers)
    if re.search(r'[+\-*/]{2,}', query.replace('--', '+').replace('+-', '-').replace('-+', '-').replace('++', '+')):
        # Allow negative numbers by checking if -- or +- patterns are valid
        normalized = query.replace('--', '+').replace('+-', '-').replace('-+', '-').replace('++', '+')
        if re.search(r'[+*/]{2,}', normalized):
            raise ValueError("Invalid operator sequence")

    # Prevent division by zero patterns
    if re.search(r'/\s*0+(?:\s|$|[+\-*/()])', query):
        raise ValueError("Division by zero")

    # Check for balanced parentheses
    paren_count = 0
    for char in query:
        if char == '(':
            paren_count += 1
        elif char == ')':
            paren_count -= 1
            if paren_count < 0:
                raise ValueError("Unbalanced parentheses")
    if paren_count != 0:
        raise ValueError("Unbalanced parentheses")

    try:
        # Use eval with restricted globals and locals for security
        result = eval(query, {"__builtins__": {}}, {})
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except (SyntaxError, NameError, TypeError):
        raise ValueError("Invalid mathematical expression")

