    allowed_builtins = {
        'len', 'str', 'int', 'float', 'bool', 'abs', 'min', 'max', 'sum',
        'round', 'range', 'list', 'tuple', 'dict', 'set'
    }

    class SafeEvaluator(ast.NodeVisitor):
        def __init__(self):
            self.variables = {}

