                    return getattr(obj, method_name)(*args)
            raise ValueError("Function call not allowed")

        def visit_List(self, node):
            return [self.visit(item) for item in node.elts]

        def visit_Tuple(self, node):
            return tuple(self.visit(item) for item in node.elts)

        def visit_Dict(self, node):
            result = {}
            for key, value in zip(node.keys, node.values):
                result[self.visit(key)] = self.visit(value)
            return result

        def visit_Set(self, node):
            return {self.visit(item) for item in node.elts}

        def visit_Subscript(self, node):
            obj = self.visit(node.value)
            index = self.visit(node.slice)
            return obj[index]

        def visit_Index(self, node):  # For Python < 3.9 compatibility
            return self.visit(node.value)

    try:
        tree = ast.parse(user_script, mode='exec')
        evaluator = SafeEvaluator()
        return evaluator.visit(tree)
    except (SyntaxError, ValueError) as e:
        raise ValueError(f"Script execution failed: {str(e)}")

