import re
import ast

def parse_and_calculate(expression: str):
    # Remove whitespace
    expression = expression.strip()

    # Validate input contains only allowed characters
    if not re.match(r'^[0-9+\-*/.() ]+$', expression):
        raise ValueError("Invalid characters in expression")

    # Parse the expression into an AST
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid syntax")

    # Define allowed node types
    allowed_nodes = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant)
    allowed_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.USub, ast.UAdd)

    # Recursively validate all nodes in the AST
    def validate_node(node):
        if not isinstance(node, allowed_nodes):
            raise ValueError("Disallowed operation")

        if isinstance(node, ast.BinOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Disallowed operator")
            validate_node(node.left)
            validate_node(node.right)
        elif isinstance(node, ast.UnaryOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Disallowed operator")
            validate_node(node.operand)
        elif isinstance(node, ast.Expression):
            validate_node(node.body)

    # Validate the entire tree
    validate_node(tree)

    # Safely evaluate the expression
    try:
        result = eval(compile(tree, '<string>', 'eval'))
        return result
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except Exception:
        raise ValueError("Calculation error")

import re
import ast
import operator

def parse_and_calculate(expression: str):
    # Remove whitespace
    expression = expression.strip()

    # Validate input contains only allowed characters
    if not re.match(r'^[0-9+\-*/.() ]+$', expression):
        raise ValueError("Invalid characters in expression")

    # Parse the expression into an AST
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError:
        raise ValueError("Invalid syntax")

    # Define allowed node types
    allowed_nodes = (ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant)
    allowed_ops = (ast.Add, ast.Sub, ast.Mult, ast.Div, ast.USub, ast.UAdd)

    # Recursively validate all nodes in the AST
    def validate_node(node):
        if not isinstance(node, allowed_nodes):
            raise ValueError("Disallowed operation")

        if isinstance(node, ast.BinOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Disallowed operator")
            validate_node(node.left)
            validate_node(node.right)
        elif isinstance(node, ast.UnaryOp):
            if not isinstance(node.op, allowed_ops):
                raise ValueError("Disallowed operator")
            validate_node(node.operand)
        elif isinstance(node, ast.Expression):
            validate_node(node.body)

    # Validate the entire tree
    validate_node(tree)

    # Safe evaluation using AST traversal
    def safe_eval(node):
        if isinstance(node, ast.Expression):
            return safe_eval(node.body)
        elif isinstance(node, ast.Constant):
            return node.value
        elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
            return node.n
        elif isinstance(node, ast.BinOp):
            left = safe_eval(node.left)
            right = safe_eval(node.right)
            if isinstance(node.op, ast.Add):
                return operator.add(left, right)
            elif isinstance(node.op, ast.Sub):
                return operator.sub(left, right)
            elif isinstance(node.op, ast.Mult):
                return operator.mul(left, right)
            elif isinstance(node.op, ast.Div):
                if right == 0:
                    raise ValueError("Division by zero")
                return operator.truediv(left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = safe_eval(node.operand)
            if isinstance(node.op, ast.USub):
                return operator.neg(operand)
            elif isinstance(node.op, ast.UAdd):
                return operator.pos(operand)

        raise ValueError("Unsupported operation")

    try:
        result = safe_eval(tree)
        return result
    except Exception as e:
        if "Division by zero" in str(e):
            raise
        raise ValueError("Calculation error")

import ast
import operator

def safe_execute_operation(operation: str):
    # Define allowed operators
    allowed_operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos
    }

    def evaluate_node(node):
        if isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # Python >= 3.8
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Only numeric constants allowed")
        elif isinstance(node, ast.BinOp):
            left = evaluate_node(node.left)
            right = evaluate_node(node.right)
            op_type = type(node.op)
            if op_type in allowed_operators:
                if op_type == ast.Div and right == 0:
                    raise ZeroDivisionError("Division by zero")
                return allowed_operators[op_type](left, right)
            else:
                raise ValueError("Operator not allowed")
        elif isinstance(node, ast.UnaryOp):
            operand = evaluate_node(node.operand)
            op_type = type(node.op)
            if op_type in allowed_operators:
                return allowed_operators[op_type](operand)
            else:
                raise ValueError("Operator not allowed")
        else:
            raise ValueError("Invalid expression")

    try:
        # Parse the operation string
        tree = ast.parse(operation, mode='eval')

        # Evaluate the parsed tree
        result = evaluate_node(tree.body)
        return result

    except (SyntaxError, ValueError, ZeroDivisionError) as e:
        raise ValueError(f"Invalid operation: {str(e)}")

def parse_user_script(script_str: str) -> str:
    import ast
    import operator

    # Define allowed operations
    allowed_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def safe_eval(node):
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float, str)):
                return node.value
            else:
                raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.BinOp):
            if type(node.op) in allowed_ops:
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                return allowed_ops[type(node.op)](left, right)
            else:
                raise ValueError("Unsupported binary operation")
        elif isinstance(node, ast.UnaryOp):
            if type(node.op) in allowed_ops:
                operand = safe_eval(node.operand)
                return allowed_ops[type(node.op)](operand)
            else:
                raise ValueError("Unsupported unary operation")
        elif isinstance(node, ast.Expression):
            return safe_eval(node.body)
        else:
            raise ValueError("Unsupported node type")

    try:
        # Parse the script string into an AST
        tree = ast.parse(script_str.strip(), mode='eval')

        # Safely evaluate the AST
        result = safe_eval(tree)

        return str(result)

    except (SyntaxError, ValueError, TypeError, ZeroDivisionError, OverflowError) as e:
        return f"Error: {str(e)}"
    except Exception:
