import ast
import operator
import math

def evaluate_user_code(code_string: str) -> str:
    try:
        # Define allowed operations and functions
        allowed_operators = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.FloorDiv: operator.floordiv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.USub: operator.neg,
            ast.UAdd: operator.pos,
        }

        allowed_functions = {
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'sum': sum,
            'pow': pow,
            'sqrt': math.sqrt,
            'sin': math.sin,
            'cos': math.cos,
            'tan': math.tan,
            'log': math.log,
            'log10': math.log10,
            'exp': math.exp,
            'ceil': math.ceil,
            'floor': math.floor,
            'pi': math.pi,
            'e': math.e,
        }

        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                op = allowed_operators.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                op = allowed_operators.get(type(node.op))
                if op is None:
                    raise ValueError("Unsupported operation")
                return op(operand)
            elif isinstance(node, ast.Call):
                if isinstance(node.func, ast.Name):
                    func_name = node.func.id
                    if func_name in allowed_functions:
                        args = [safe_eval(arg) for arg in node.args]
                        return allowed_functions[func_name](*args)
                raise ValueError("Unsupported function")
            elif isinstance(node, ast.Name):
                if node.id in allowed_functions:
                    return allowed_functions[node.id]
                raise ValueError("Unsupported variable")
            elif isinstance(node, ast.List):
                return [safe_eval(item) for item in node.elts]
            elif isinstance(node, ast.Tuple):
                return tuple(safe_eval(item) for item in node.elts)
            else:
                raise ValueError("Unsupported syntax")

        # Parse and evaluate the code
        tree = ast.parse(code_string, mode='eval')
        result = safe_eval(tree)
        return str(result)

    except Exception as e:
        return f"Error: {str(e)}"
